import json

# Load Europe metadata
metadata_file = locals()['var_functions.query_db:6']
with open(metadata_file, 'r') as f:
    europe_metadata = json.load(f)

# Create year-to-article_ids mapping
europe_articles_by_year = {}
for article in europe_metadata:
    year = article['publication_date'][:4]
    article_id = str(article['article_id'])
    if year not in europe_articles_by_year:
        europe_articles_by_year[year] = []
    europe_articles_by_year[year].append(article_id)

print('__RESULT__:')
print(json.dumps({
    'years': list(europe_articles_by_year.keys()),
    'total_articles_by_year': {year: len(ids) for year, ids in europe_articles_by_year.items()}
}))

